import asyncio
import httpx

@app.get("/api/dashboard")
async def get_dashboard(user_id: str):
    async with httpx.AsyncClient(timeout=1.5) as client:
        user_task = client.get(f"http://user-svc/users/{user_id}")
        orders_task = client.get(f"http://order-svc/users/{user_id}/orders?limit=5")
        notif_task = client.get(f"http://notif-svc/users/{user_id}/unread")

        user, orders, notif = await asyncio.gather(
            user_task, orders_task, notif_task,
            return_exceptions=True
        )

    def safe(r):
        if isinstance(r, Exception):
            return {"error": "partial", "detail": str(r)}
        return r.json()

    return {"user": safe(user), "orders": safe(orders), "notifications": safe(notif)}
